// The ...numbers parameter collects all passed arguments into an array
function calcSum(...numbers) {
    let result = 0;

    // Iterating through the generated array
    for (let i = 0; i < numbers.length; i++) {
        result += numbers[i];
    }

    return `Final Result: ${result}`;
}

